weights_input = input()
weights = [] 

for weight in weights_input.split():
    weights += [int(weight)] 

target = int(input())

for i in range(len(weights)):
    for j in range(i + 1, len(weights)):
        if weights[i] + weights[j] == target:
            print(i, j)
            break
    if weights[i] + weights[j] == target:
        break
